import React, { useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext.js';
import { useCart } from '../context/CartContext';
import Cart from './Cart';

const Navbar = () => {
  const { user, logout, error } = useAuth();
  const { count } = useCart();
  const navigate = useNavigate();
  const location = useLocation();
  const [cartOpen, setCartOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/auth');
  };

  const isActive = (path) => location.pathname === path;

  return (
    <>
      <nav style={styles.nav}>
        <Link to="/" style={styles.logo}>Foody.</Link>

        <div style={styles.links}>
          <Link to="/" style={{ ...styles.link, ...(isActive('/') && styles.linkActive) }}>Home</Link>
          <Link to="/orders" style={{ ...styles.link, ...(isActive('/orders') && styles.linkActive) }}>My Orders</Link>

          {user?.role === 'admin' && (
            <Link to="/admin" style={{ ...styles.link, ...(isActive('/admin') && styles.linkActive) }}>Admin</Link>
          )}
        </div>

        <div style={styles.right}>
          <span>{user?.fullName?.split(' ')[0]}</span>

          <button onClick={() => setCartOpen(true)}>
            🛒 {count}
          </button>

          <button onClick={handleLogout}>Logout</button>
        </div>
      </nav>

      {/* 🔥 ERROR MESSAGE */}
      {error && (
        <div style={{
          background: '#FCEBEB',
          color: '#A32D2D',
          padding: '10px',
          textAlign: 'center'
        }}>
          ❌ {error}
        </div>
      )}

      {cartOpen && <Cart onClose={() => setCartOpen(false)} />}
    </>
  );
};

export default Navbar;
